     5→
     6→// This file implements checkpoint persistence for the in-memory metric store.
     7→//
     8→// Checkpoints enable graceful restarts by periodically saving in-memory metric
     9→// data to disk in JSON or binary format. The checkpoint system:
    10→//
    11→// Key Features:
    12→//   - Periodic background checkpointing via the Checkpointing() worker
    13→//   - Two format families: JSON (human-readable) and WAL+binary (compact, crash-safe)
    14→//   - Parallel checkpoint creation and loading using worker pools
    15→//   - Hierarchical file organization: checkpoint_dir/cluster/host/timestamp.{json|bin}
    16→//   - WAL file: checkpoint_dir/cluster/host/current.wal (append-only, per-entry)
    17→//   - Only saves unarchived data (archived data is already persisted elsewhere)
    18→//   - GC optimization during loading to prevent excessive heap growth
    19→//
    20→// Checkpoint Workflow:
    21→//  1. Init() loads checkpoints within retention window at startup
    22→//  2. Checkpointing() worker periodically saves new data
    23→//  3. Shutdown() writes final checkpoint before exit
    24→//
    25→// File Organization:
    26→//
    27→//	checkpoints/
    28→//	  cluster1/
    29→//	    host001/
    30→//	      1234567890.json  (JSON format: full subtree snapshot)
    31→//	      1234567890.bin   (binary format: full subtree snapshot)
    32→//	      current.wal      (WAL format: append-only per-entry log)
    33→//	    host002/
    34→//	      ...
    35→package metricstore
    36→
    37→import (
    38→	"bufio"
    39→	"context"
    40→	"encoding/json"
    41→	"errors"
    42→	"fmt"
    43→	"io/fs"
    44→	"os"
    45→	"path"
    46→	"path/filepath"
    47→	"sort"
    48→	"strconv"
    49→	"strings"
    50→	"sync"
    51→	"sync/atomic"
    52→	"time"
    53→
    54→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
    55→	"github.com/ClusterCockpit/cc-lib/v2/schema"
    56→)
    57→
    58→const (
    59→	CheckpointFilePerms = 0o644                    // File permissions for checkpoint files
    60→	CheckpointDirPerms  = 0o755                    // Directory permissions for checkpoint directories
    61→	GCTriggerInterval   = DefaultGCTriggerInterval // Interval for triggering GC during checkpoint loading
    62→)
    63→
    64→// CheckpointMetrics represents metric data in a checkpoint file.
    65→// Whenever the structure changes, update MarshalJSON as well!
    66→type CheckpointMetrics struct {
    67→	Data      []schema.Float `json:"data"`
    68→	Frequency int64          `json:"frequency"`
    69→	Start     int64          `json:"start"`
    70→}
    71→
    72→// CheckpointFile represents the hierarchical structure of a checkpoint file.
    73→// It mirrors the Level tree structure from the MemoryStore.
    74→type CheckpointFile struct {
    75→	Metrics  map[string]*CheckpointMetrics `json:"metrics"`
    76→	Children map[string]*CheckpointFile    `json:"children"`
    77→	From     int64                         `json:"from"`
    78→	To       int64                         `json:"to"`
    79→}
    80→
    81→// lastCheckpoint tracks the timestamp of the last checkpoint creation.
    82→var (
    83→	lastCheckpoint   time.Time
    84→	lastCheckpointMu sync.Mutex
    85→)
    86→
    87→// Checkpointing starts a background worker that periodically saves metric data to disk.
    88→//
    89→// Format behaviour:
    90→//   - "json": Periodic checkpointing based on Keys.Checkpoints.Interval
    91→//   - "wal":  Periodic binary snapshots + WAL rotation at Keys.Checkpoints.Interval
    92→func Checkpointing(wg *sync.WaitGroup, ctx context.Context) {
    93→	lastCheckpointMu.Lock()
    94→	lastCheckpoint = time.Now()
    95→	lastCheckpointMu.Unlock()
    96→
    97→	ms := GetMemoryStore()
    98→
    99→	wg.Go(func() {
   100→
   101→		d, err := time.ParseDuration(Keys.Checkpoints.Interval)
   102→		if err != nil {
   103→			cclog.Fatalf("[METRICSTORE]> invalid checkpoint interval '%s': %s", Keys.Checkpoints.Interval, err.Error())
   104→		}
   105→		if d <= 0 {
   106→			cclog.Warnf("[METRICSTORE]> checkpoint interval is zero or negative (%s), checkpointing disabled", d)
   107→			return
   108→		}
   109→
   110→		ticker := time.NewTicker(d)
   111→		defer ticker.Stop()
   112→
   113→		for {
   114→			select {
   115→			case <-ctx.Done():
   116→				return
   117→			case <-ticker.C:
   118→				lastCheckpointMu.Lock()
   119→				from := lastCheckpoint
   120→				lastCheckpointMu.Unlock()
   121→
   122→				now := time.Now()
   123→				cclog.Infof("[METRICSTORE]> start checkpointing (starting at %s)...", from.Format(time.RFC3339))
   124→
   125→				if Keys.Checkpoints.FileFormat == "wal" {
   126→					n, hostDirs, err := ms.ToCheckpointWAL(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
   127→					if err != nil {
   128→						cclog.Errorf("[METRICSTORE]> binary checkpointing failed: %s", err.Error())
   129→					} else {
   130→						cclog.Infof("[METRICSTORE]> done: %d binary snapshot files created", n)
   131→						lastCheckpointMu.Lock()
   132→						lastCheckpoint = now
   133→						lastCheckpointMu.Unlock()
   134→						// Rotate WAL files for successfully checkpointed hosts.
   135→						RotateWALFiles(hostDirs)
   136→					}
   137→				} else {
   138→					n, err := ms.ToCheckpoint(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
   139→					if err != nil {
   140→						cclog.Errorf("[METRICSTORE]> checkpointing failed: %s", err.Error())
   141→					} else {
   142→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files created", n)
   143→						lastCheckpointMu.Lock()
   144→						lastCheckpoint = now
   145→						lastCheckpointMu.Unlock()
   146→					}
   147→				}
   148→			}
   149→		}
   150→	})
   151→}
   152→
   153→// MarshalJSON provides optimized JSON encoding for CheckpointMetrics.
   154→//
   155→// Since schema.Float has custom MarshalJSON, serializing []Float has significant overhead.
   156→// This method manually constructs JSON to avoid allocations and interface conversions.
   157→func (cm *CheckpointMetrics) MarshalJSON() ([]byte, error) {
   158→	buf := make([]byte, 0, 128+len(cm.Data)*8)
   159→	buf = append(buf, `{"frequency":`...)
   160→	buf = strconv.AppendInt(buf, cm.Frequency, 10)
   161→	buf = append(buf, `,"start":`...)
   162→	buf = strconv.AppendInt(buf, cm.Start, 10)
   163→	buf = append(buf, `,"data":[`...)
   164→	for i, x := range cm.Data {
   165→		if i != 0 {
   166→			buf = append(buf, ',')
   167→		}
   168→		if x.IsNaN() {
   169→			buf = append(buf, `null`...)
   170→		} else {
   171→			buf = strconv.AppendFloat(buf, float64(x), 'f', 1, 32)
   172→		}
   173→	}
   174→	buf = append(buf, `]}`...)
   175→	return buf, nil
   176→}
   177→
   178→// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
   179→//
   180→// Metrics at root and cluster levels are skipped. One file per host is created.
   181→// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
   182→// at a time, allowing concurrent writes/reads to other hosts.
   183→//
   184→// Returns the number of checkpoint files created and any errors encountered.
   185→func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
   186→	// Pre-calculate capacity by counting cluster/host pairs
   187→	m.root.lock.RLock()
   188→	totalHosts := 0
   189→	for _, l1 := range m.root.children {
   190→		l1.lock.RLock()
   191→		totalHosts += len(l1.children)
   192→		l1.lock.RUnlock()
   193→	}
   194→	m.root.lock.RUnlock()
   195→
   196→	levels := make([]*Level, 0, totalHosts)
   197→	selectors := make([][]string, 0, totalHosts)
   198→
   199→	m.root.lock.RLock()
   200→	for sel1, l1 := range m.root.children {
   201→		l1.lock.RLock()
   202→		for sel2, l2 := range l1.children {
   203→			levels = append(levels, l2)
   204→			selectors = append(selectors, []string{sel1, sel2})
   205→		}
   206→		l1.lock.RUnlock()
   207→	}
   208→	m.root.lock.RUnlock()
   209→
   210→	type workItem struct {
   211→		level    *Level
   212→		dir      string
   213→		selector []string
   214→	}
   215→
   216→	n, errs := int32(0), int32(0)
   217→
   218→	var wg sync.WaitGroup
   219→	wg.Add(Keys.NumWorkers)
   220→	work := make(chan workItem, Keys.NumWorkers*2)
   221→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   222→		go func() {
   223→			defer wg.Done()
   224→
   225→			for workItem := range work {
   226→				if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
   227→					if err == ErrNoNewArchiveData {
   228→						continue
   229→					}
   230→
   231→					cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
   232→					atomic.AddInt32(&errs, 1)
   233→				} else {
   234→					atomic.AddInt32(&n, 1)
   235→				}
   236→			}
   237→		}()
   238→	}
   239→
   240→	for i := 0; i < len(levels); i++ {
   241→		dir := path.Join(dir, path.Join(selectors[i]...))
   242→		work <- workItem{
   243→			level:    levels[i],
   244→			dir:      dir,
   245→			selector: selectors[i],
   246→		}
   247→	}
   248→
   249→	close(work)
   250→	wg.Wait()
   251→
   252→	if errs > 0 {
   253→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
   254→	}
   255→	return int(n), nil
   256→}
   257→
   258→// toCheckpointFile recursively converts a Level tree to CheckpointFile structure.
   259→// Skips metrics that are already archived. Returns nil if no unarchived data exists.
   260→func (l *Level) toCheckpointFile(from, to int64, m *MemoryStore) (*CheckpointFile, error) {
   261→	l.lock.RLock()
   262→	defer l.lock.RUnlock()
   263→
   264→	retval := &CheckpointFile{
   265→		From:     from,
   266→		To:       to,
   267→		Metrics:  make(map[string]*CheckpointMetrics),
   268→		Children: make(map[string]*CheckpointFile),
   269→	}
   270→
   271→	for metric, minfo := range m.Metrics {
   272→		b := l.metrics[minfo.offset]
   273→		if b == nil {
   274→			continue
   275→		}
   276→
   277→		allArchived := true
   278→		b.iterFromTo(from, to, func(b *buffer) error {
   279→			if !b.archived {
   280→				allArchived = false
   281→				return fmt.Errorf("stop") // Early termination signal
   282→			}
   283→			return nil
   284→		})
   285→
   286→		if allArchived {
   287→			continue
   288→		}
   289→
   290→		data := make([]schema.Float, (to-from)/b.frequency+1)
   291→		data, start, end, err := b.read(from, to, data)
   292→		if err != nil {
   293→			return nil, err
   294→		}
   295→
   296→		for i := int((end - start) / b.frequency); i < len(data); i++ {
   297→			data[i] = schema.NaN
   298→		}
   299→
   300→		retval.Metrics[metric] = &CheckpointMetrics{
   301→			Frequency: b.frequency,
   302→			Start:     start,
   303→			Data:      data,
   304→		}
   305→	}
   306→
   307→	for name, child := range l.children {
   308→		val, err := child.toCheckpointFile(from, to, m)
   309→		if err != nil {
   310→			return nil, err
   311→		}
   312→
   313→		if val != nil {
   314→			retval.Children[name] = val
   315→		}
   316→	}
   317→
   318→	if len(retval.Children) == 0 && len(retval.Metrics) == 0 {
   319→		return nil, nil
   320→	}
   321→
   322→	return retval, nil
   323→}
   324→
   325→// toCheckpoint writes a Level's data to a JSON checkpoint file.
   326→// Creates directory if needed. Returns ErrNoNewArchiveData if nothing to save.
   327→func (l *Level) toCheckpoint(dir string, from, to int64, m *MemoryStore) error {
   328→	cf, err := l.toCheckpointFile(from, to, m)
   329→	if err != nil {
   330→		return err
   331→	}
   332→
   333→	if cf == nil {
   334→		return ErrNoNewArchiveData
   335→	}
   336→
   337→	filepath := path.Join(dir, fmt.Sprintf("%d.json", from))
   338→	f, err := os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   339→	if err != nil && os.IsNotExist(err) {
   340→		err = os.MkdirAll(dir, CheckpointDirPerms)
   341→		if err == nil {
   342→			f, err = os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   343→		}
   344→	}
   345→	if err != nil {
   346→		return err
   347→	}
   348→	defer f.Close()
   349→
   350→	bw := bufio.NewWriter(f)
   351→	if err = json.NewEncoder(bw).Encode(cf); err != nil {
   352→		return err
   353→	}
   354→
   355→	return bw.Flush()
   356→}
   357→
   358→// enqueueCheckpointHosts traverses checkpoint directory and enqueues cluster/host pairs.
   359→// Returns error if directory structure is invalid.
   360→func enqueueCheckpointHosts(dir string, work chan<- [2]string) error {
   361→	clustersDir, err := os.ReadDir(dir)
   362→	if err != nil {
   363→		return err
   364→	}
   365→
   366→	for _, clusterDir := range clustersDir {
   367→		if !clusterDir.IsDir() {
   368→			return errors.New("[METRICSTORE]> expected only directories at first level of checkpoints/ directory")
   369→		}
   370→
   371→		hostsDir, err := os.ReadDir(filepath.Join(dir, clusterDir.Name()))
   372→		if err != nil {
   373→			return err
   374→		}
   375→
   376→		for _, hostDir := range hostsDir {
   377→			if !hostDir.IsDir() {
   378→				return errors.New("[METRICSTORE]> expected only directories at second level of checkpoints/ directory")
   379→			}
   380→
   381→			work <- [2]string{clusterDir.Name(), hostDir.Name()}
   382→		}
   383→	}
   384→
   385→	return nil
   386→}
   387→
   388→// FromCheckpoint loads checkpoint files from disk into memory in parallel.
   389→//
   390→// Uses worker pool to load cluster/host combinations. Returns number of files
   391→// loaded and any errors.
   392→func (m *MemoryStore) FromCheckpoint(dir string, from int64) (int, error) {
   393→	var wg sync.WaitGroup
   394→	work := make(chan [2]string, Keys.NumWorkers*4)
   395→	n, errs := int32(0), int32(0)
   396→
   397→	wg.Add(Keys.NumWorkers)
   398→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   399→		go func() {
   400→			defer wg.Done()
   401→			for host := range work {
   402→				lvl := m.root.findLevelOrCreate(host[:], len(m.Metrics))
   403→				nn, err := lvl.fromCheckpoint(m, filepath.Join(dir, host[0], host[1]), from)
   404→				if err != nil {
   405→					cclog.Errorf("[METRICSTORE]> error while loading checkpoints for %s/%s: %s", host[0], host[1], err.Error())
   406→					atomic.AddInt32(&errs, 1)
   407→				}
   408→				atomic.AddInt32(&n, int32(nn))
   409→			}
   410→		}()
   411→	}
   412→
   413→	err := enqueueCheckpointHosts(dir, work)
   414→	close(work)
   415→	wg.Wait()
   416→
   417→	if err != nil {
   418→		return int(n), err
   419→	}
   420→
   421→	if errs > 0 {
   422→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
   423→	}
   424→	return int(n), nil
   425→}
   426→
   427→// FromCheckpointFiles is the main entry point for loading checkpoints at startup.
   428→//
   429→// Creates checkpoint directory if it doesn't exist. This function must be called
   430→// before any writes or reads, and can only be called once.
   431→func (m *MemoryStore) FromCheckpointFiles(dir string, from int64) (int, error) {
   432→	if _, err := os.Stat(dir); os.IsNotExist(err) {
   433→		err := os.MkdirAll(dir, CheckpointDirPerms)
   434→		if err != nil {
   435→			cclog.Fatalf("[METRICSTORE]> Error creating directory: %#v\n", err)
   436→		}
   437→		cclog.Debugf("[METRICSTORE]> %#v Directory created successfully", dir)
   438→	}
   439→
   440→	return m.FromCheckpoint(dir, from)
   441→}
   442→
   443→func (l *Level) loadJSONFile(m *MemoryStore, f *os.File, from int64) error {
   444→	br := bufio.NewReader(f)
   445→	cf := &CheckpointFile{}
   446→	if err := json.NewDecoder(br).Decode(cf); err != nil {
   447→		return err
   448→	}
   449→
   450→	if cf.To != 0 && cf.To < from {
   451→		return nil
   452→	}
   453→
   454→	if err := l.loadFile(cf, m); err != nil {
   455→		return err
   456→	}
   457→
   458→	return nil
   459→}
   460→
   461→func (l *Level) loadFile(cf *CheckpointFile, m *MemoryStore) error {
   462→	for name, metric := range cf.Metrics {
   463→		n := len(metric.Data)
   464→		b := &buffer{
   465→			frequency: metric.Frequency,
   466→			start:     metric.Start,
   467→			data:      metric.Data[0:n:n],
   468→			prev:      nil,
   469→			next:      nil,
   470→			archived:  true,
   471→		}
   472→
   473→		minfo, ok := m.Metrics[name]
   474→		if !ok {
   475→			continue
   476→		}
   477→
   478→		prev := l.metrics[minfo.offset]
   479→		if prev == nil {
   480→			l.metrics[minfo.offset] = b
   481→		} else {
   482→			if prev.start > b.start {
   483→				return fmt.Errorf("[METRICSTORE]> buffer start time %d is before previous buffer start %d", b.start, prev.start)
   484→			}
   485→
   486→			b.prev = prev
   487→			prev.next = b
   488→		}
   489→		l.metrics[minfo.offset] = b
   490→	}
   491→
   492→	if len(cf.Children) > 0 && l.children == nil {
   493→		l.children = make(map[string]*Level)
   494→	}
   495→
   496→	for sel, childCf := range cf.Children {
   497→		child, ok := l.children[sel]
   498→		if !ok {
   499→			child = &Level{
   500→				metrics:  make([]*buffer, len(m.Metrics)),
   501→				children: nil,
   502→			}
   503→			l.children[sel] = child
   504→		}
   505→
   506→		if err := child.loadFile(childCf, m); err != nil {
   507→			return err
   508→		}
   509→	}
   510→
   511→	return nil
   512→}
   513→
   514→// fromCheckpoint loads all checkpoint files (JSON, binary snapshot, WAL) for a
   515→// single host directory. Snapshot files are loaded first (sorted by timestamp),
   516→// then current.wal is replayed on top.
   517→func (l *Level) fromCheckpoint(m *MemoryStore, dir string, from int64) (int, error) {
   518→	direntries, err := os.ReadDir(dir)
   519→	if err != nil {
   520→		if os.IsNotExist(err) {
   521→			return 0, nil
   522→		}
   523→		return 0, err
   524→	}
   525→
   526→	allFiles := make([]fs.DirEntry, 0)
   527→	var walEntry fs.DirEntry
   528→	filesLoaded := 0
   529→
   530→	for _, e := range direntries {
   531→		if e.IsDir() {
   532→			// Legacy: skip subdirectories (only used by old Avro format).
   533→			// These are ignored; their data is not loaded.
   534→			cclog.Debugf("[METRICSTORE]> skipping subdirectory %s in checkpoint dir %s", e.Name(), dir)
   535→			continue
   536→		}
   537→
   538→		name := e.Name()
   539→		if strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".bin") {
   540→			allFiles = append(allFiles, e)
   541→		} else if name == "current.wal" {
   542→			walEntry = e
   543→		}
   544→		// Silently ignore other files (e.g., .tmp, .bin.tmp from interrupted writes).
   545→	}
   546→
   547→	files, err := findFiles(allFiles, from, true)
   548→	if err != nil {
   549→		return filesLoaded, err
   550→	}
   551→
   552→	loaders := map[string]func(*MemoryStore, *os.File, int64) error{
   553→		".json": l.loadJSONFile,
   554→		".bin":  l.loadBinaryFile,
   555→	}
   556→
   557→	for _, filename := range files {
   558→		ext := filepath.Ext(filename)
   559→		loader := loaders[ext]
   560→		if loader == nil {
   561→			cclog.Warnf("[METRICSTORE]> unknown extension for checkpoint file %s", filename)
   562→			continue
   563→		}
   564→
   565→		err := func() error {
   566→			f, err := os.Open(path.Join(dir, filename))
   567→			if err != nil {
   568→				return err
   569→			}
   570→			defer f.Close()
   571→			return loader(m, f, from)
   572→		}()
   573→		if err != nil {
   574→			return filesLoaded, err
   575→		}
   576→		filesLoaded++
   577→	}
   578→
   579→	// Replay WAL after all snapshot files so it fills in data since the last snapshot.
   580→	if walEntry != nil {
   581→		err := func() error {
   582→			f, err := os.Open(path.Join(dir, walEntry.Name()))
   583→			if err != nil {
   584→				return err
   585→			}
   586→			defer f.Close()
   587→			return l.loadWALFile(m, f, from)
   588→		}()
   589→		if err != nil {
   590→			// WAL errors are non-fatal: the snapshot already loaded the bulk of data.
   591→			cclog.Warnf("[METRICSTORE]> WAL replay error for %s: %v (data since last snapshot may be missing)", dir, err)
   592→		} else {
   593→			filesLoaded++
   594→		}
   595→	}
   596→
   597→	return filesLoaded, nil
   598→}
   599→
   600→// parseTimestampFromFilename extracts a Unix timestamp from a checkpoint filename.
   601→// Supports ".json" (format: "<ts>.json") and ".bin" (format: "<ts>.bin").
   602→func parseTimestampFromFilename(name string) (int64, error) {
   603→	switch {
   604→	case strings.HasSuffix(name, ".json"):
   605→		return strconv.ParseInt(name[:len(name)-5], 10, 64)
   606→	case strings.HasSuffix(name, ".bin"):
   607→		return strconv.ParseInt(name[:len(name)-4], 10, 64)
   608→	default:
   609→		return 0, fmt.Errorf("unknown checkpoint extension for file %q", name)
   610→	}
   611→}
   612→
   613→// findFiles returns filenames from direntries whose timestamps satisfy the filter.
   614→// If findMoreRecentFiles is true, returns files with timestamps >= t (plus the
   615→// last file before t if t falls between two files).
   616→func findFiles(direntries []fs.DirEntry, t int64, findMoreRecentFiles bool) ([]string, error) {
   617→	nums := map[string]int64{}
   618→	for _, e := range direntries {
   619→		name := e.Name()
   620→		if !strings.HasSuffix(name, ".json") && !strings.HasSuffix(name, ".bin") {
   621→			continue
   622→		}
   623→
   624→		ts, err := parseTimestampFromFilename(name)
   625→		if err != nil {
   626→			return nil, err
   627→		}
   628→		nums[name] = ts
   629→	}
   630→
   631→	sort.Slice(direntries, func(i, j int) bool {
   632→		a, b := direntries[i], direntries[j]
   633→		return nums[a.Name()] < nums[b.Name()]
   634→	})
   635→
   636→	if len(nums) == 0 {
   637→		return nil, nil
   638→	}
   639→
   640→	filenames := make([]string, 0)
   641→
   642→	for i, e := range direntries {
   643→		ts1 := nums[e.Name()]
   644→
   645→		if findMoreRecentFiles && t <= ts1 {
   646→			filenames = append(filenames, e.Name())
   647→		} else if !findMoreRecentFiles && ts1 <= t && ts1 != 0 {
   648→			filenames = append(filenames, e.Name())
   649→		}
   650→
   651→		if i == len(direntries)-1 {
   652→			continue
   653→		}
   654→
   655→		enext := direntries[i+1]
   656→		ts2 := nums[enext.Name()]
   657→
   658→		if findMoreRecentFiles {
   659→			if ts1 < t && t < ts2 {
   660→				filenames = append(filenames, e.Name())
   661→			}
   662→		}
   663→	}
   664→
   665→	return filenames, nil
   666→}
   667→

